import (
	"container/heap"
)

type Item struct {
	node      int
	totalCost int64
	minCost   int64
	index     int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].minCost > pq[j].minCost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	adj := make([][][2]int64, n)
	for _, edge := range edges {
		u := int(edge[0])
		v := int(edge[1])
		cost := edge[2]
		adj[u] = append(adj[u], [2]int64{int64(v), cost})
	}

	maxScore := int64(-1)
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{node: 0, totalCost: 0, minCost: 1 << 62})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		node := item.node
		totalCost := item.totalCost
		minCost := item.minCost

		if node == n-1 {
			if totalCost <= k {
				if minCost == 1<<62 {
					if maxScore == -1 {
						maxScore = -1
					}
				} else {
					if minCost > maxScore {
						maxScore = minCost
					}
				}
			}
			continue
		}

		for _, neighbor := range adj[node] {
			v := int(neighbor[0])
			cost := neighbor[1]
			if !online[v] && v != n-1 {
				continue
			}
			newTotalCost := totalCost + cost
			if newTotalCost > k {
				continue
			}
			newMinCost := minCost
			if cost < newMinCost {
				newMinCost = cost
			}
			heap.Push(&pq, &Item{node: v, totalCost: newTotalCost, minCost: newMinCost})
		}
	}

	return maxScore
}
